@namespace Lumeo
@implements IAsyncDisposable

<div id="@_handleId"
     role="separator"
     aria-orientation="@(IsHorizontal ? "vertical" : "horizontal")"
     aria-valuenow="@LeadingPanelValue"
     aria-valuemin="@LeadingPanelMin"
     aria-valuemax="@LeadingPanelMax"
     tabindex="0"
     class="@CssClass"
     data-panel-group-direction="@DirectionString"
     @onkeydown="OnKeyDown"
     @attributes="AdditionalAttributes">
    @if (WithHandle)
    {
        @if (Context.Direction == Lumeo.Orientation.Horizontal)
        {
            <div class="z-10 flex h-4 w-3 items-center justify-center rounded-sm border bg-border">
                <SvgGlyph Svg="@(LumeoIcons.GripVertical)" class="h-2.5 w-2.5" />
            </div>
        }
        else
        {
            <div class="z-10 flex h-3 w-4 items-center justify-center rounded-sm border bg-border">
                <SvgGlyph Svg="@(LumeoIcons.GripHorizontal)" class="h-2.5 w-2.5" />
            </div>
        }
    }
</div>

@inject IComponentInteropService Interop
@inject ThemeService Theme

@code {
    [CascadingParameter] public ResizablePanelGroup.ResizablePanelGroupContext Context { get; set; } = default!;

    // A scoped <DirectionProvider> cascades its direction here; when present it
    // wins over the global ThemeService so a subtree can be RTL even if the app
    // is LTR (and vice versa). Null when no provider wraps this handle — then
    // the ambient theme direction applies.
    [CascadingParameter(Name = "LumeoDirection")] private LayoutDirection? ScopedDirection { get; set; }
    private LayoutDirection EffectiveDirection => ScopedDirection ?? Theme.CurrentDirection;

    /// <summary>Index of the leading panel this handle resizes (the one immediately before it in the group). Dragging/arrow keys resize this panel against the panel at <c>PanelIndex + 1</c>.</summary>
    [Parameter, EditorRequired] public int PanelIndex { get; set; }

    /// <summary>When <c>true</c>, renders a small grip glyph centered on the handle for a more discoverable drag affordance.</summary>
    [Parameter] public bool WithHandle { get; set; }

    /// <summary>Additional CSS classes merged onto the handle.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures any unmatched attributes and applies them to the handle.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _handleId = LumeoIds.New("resizable-handle");

    private bool IsHorizontal => Context?.Direction == Lumeo.Orientation.Horizontal;

    private string DirectionString =>
        Context.Direction == Lumeo.Orientation.Horizontal ? "horizontal" : "vertical";

    // aria-valuenow/min/max describe the LEADING panel (PanelIndex) — the same
    // number drags and arrow keys steer. Mirrors SplitterDivider: min/max must
    // account for BOTH neighbours, since the leading panel can't grow past the
    // point where the trailing panel would drop below its MinSize (and vice
    // versa) — HandleDrag clamps to exactly these limits.
    private int LeadingPanelValue => (int)Math.Round(Context?.GetPanelSize(PanelIndex) ?? 0);

    private int LeadingPanelMin
    {
        get
        {
            if (Context is null) return 0;
            var (ownMin, _) = Context.GetPanelConstraints(PanelIndex);
            var (_, trailingMax) = Context.GetPanelConstraints(PanelIndex + 1);
            var pairTotal = Context.GetPanelSize(PanelIndex) + Context.GetPanelSize(PanelIndex + 1);
            return (int)Math.Round(Math.Max(ownMin, pairTotal - trailingMax));
        }
    }

    private int LeadingPanelMax
    {
        get
        {
            if (Context is null) return 100;
            var (_, ownMax) = Context.GetPanelConstraints(PanelIndex);
            var (trailingMin, _) = Context.GetPanelConstraints(PanelIndex + 1);
            var pairTotal = Context.GetPanelSize(PanelIndex) + Context.GetPanelSize(PanelIndex + 1);
            return (int)Math.Round(Math.Min(ownMax, pairTotal - trailingMin));
        }
    }

    private string CssClass =>
        Context.Direction == Lumeo.Orientation.Horizontal
            ? Cx.Merge("relative flex w-px items-center justify-center bg-border after:absolute after:inset-y-0 after:-start-1 after:-end-1 after:content-[''] hover:bg-primary/50 focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring focus-visible:ring-offset-1 cursor-col-resize", Class)
            : Cx.Merge("relative flex h-px w-full items-center justify-center bg-border after:absolute after:inset-x-0 after:-top-1 after:-bottom-1 after:content-[''] hover:bg-primary/50 focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring focus-visible:ring-offset-1 cursor-row-resize", Class);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;
        try
        {
            var direction = Context.Direction == Lumeo.Orientation.Horizontal
                ? "horizontal"
                : "vertical";

            await Interop.RegisterResizeHandle(
                _handleId,
                direction,
                async (delta) =>
                {
                    await Context.OnHandleDrag.InvokeAsync((PanelIndex, delta));
                },
                async () =>
                {
                    await InvokeAsync(StateHasChanged);
                }
            );
            // Suppress page scroll for the resize arrows ONLY — a blanket
            // @onkeydown:preventDefault on a tabindex="0" element also
            // cancels Tab: a WCAG 2.1.2 keyboard trap (same fix as
            // SplitterDivider).
            var keys = IsHorizontal
                ? new[] { "ArrowLeft", "ArrowRight" }
                : new[] { "ArrowUp", "ArrowDown" };
            await Interop.RegisterPreventDefaultKeys(
                _handleId,
                keys.Select(k => new PreventDefaultKeyRule(k)).ToArray());
            _pdRegistered = true;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    private bool _pdRegistered;

    // Keyboard resize: arrow keys move the handle by a fixed 10px step through
    // the same group resize path used by pointer drags (min/max clamping
    // happens there). Page scroll for the arrows is suppressed via the
    // key-selective JS registration above (Tab must pass). In RTL,
    // ArrowLeft/Right are swapped for horizontal groups so the key that
    // points toward the visual "start" always shrinks the leading panel.
    private async Task OnKeyDown(KeyboardEventArgs e)
    {
        if (Context is null) return;
        const double step = 10.0;

        var isRtl = IsHorizontal && EffectiveDirection == LayoutDirection.Rtl;
        var delta = (IsHorizontal, e.Key) switch
        {
            (true,  "ArrowLeft")  => isRtl ?  step : -step,
            (true,  "ArrowRight") => isRtl ? -step :  step,
            (false, "ArrowUp")    => -step,
            (false, "ArrowDown")  =>  step,
            _ => 0.0
        };

        if (delta != 0.0)
        {
            await Context.OnHandleDrag.InvokeAsync((PanelIndex, delta));
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (!_pdRegistered) return;
        try
        {
            await Interop.UnregisterResizeHandle(_handleId);
            await Interop.UnregisterPreventDefaultKeys(_handleId);
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }
}

namespace Lumeo;

/// <summary>
/// JSON-serializable snapshot of a <see cref="ResizablePanelGroup"/>'s current
/// panel sizes (percentages, in panel order). Used to persist a user-dragged
/// layout across sessions in tandem with
/// <see cref="ResizablePanelGroup.SavedLayout"/> and
/// <see cref="ResizablePanelGroup.OnLayout"/>.
/// </summary>
/// <param name="Sizes">
/// The panel sizes as percentages of the group, in the same order the panels
/// are declared (matching <see cref="ResizablePanel.Order"/>). Should sum to
/// ~100.
/// </param>
/// <remarks>
/// Mirrors <see cref="TabsLayout"/>: the consumer owns persistence. On init,
/// pass a previously-saved <see cref="ResizableLayout"/> to
/// <see cref="ResizablePanelGroup.SavedLayout"/>; on every resize the group
/// raises <see cref="ResizablePanelGroup.OnLayout"/> with the new snapshot for
/// the consumer to store (local storage, a server, …).
/// </remarks>
public sealed record ResizableLayout(IReadOnlyList<double> Sizes);

@namespace Lumeo
@implements IDisposable

<div class="@CssClass"
     style="flex: @(Size.ToString("F2", System.Globalization.CultureInfo.InvariantCulture)) 1 0; min-width: 0; min-height: 0; overflow: auto;"
     data-collapsed="@(IsCollapsed ? "true" : null)"
     @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [CascadingParameter] public ResizablePanelGroup.ResizablePanelGroupContext Context { get; set; } = default!;

    /// <summary>This panel's index within the group, also used as its key when registering/unregistering with the group and by <see cref="ResizableHandle.PanelIndex"/> to identify which panel a handle resizes.</summary>
    [Parameter] public int Order { get; set; }

    /// <summary>Initial percentage size of the panel, consumed by the group to seed the shared size list when the group has no <c>DefaultSizes</c> of its own. Defaults to <c>50</c>.</summary>
    [Parameter] public double DefaultSize { get; set; } = 50;

    /// <summary>Minimum percentage size a handle drag can shrink this panel to. Defaults to <c>10</c>.</summary>
    [Parameter] public double MinSize { get; set; } = 10;

    /// <summary>Maximum percentage size a handle drag can grow this panel to. Defaults to <c>90</c>.</summary>
    [Parameter] public double MaxSize { get; set; } = 90;

    /// <summary>
    /// When true, the panel can collapse to <see cref="CollapsedSize"/> — by
    /// dragging its handle below (roughly) half the MinSize, or via the
    /// group's <c>ToggleCollapse</c> from the cascading context. Restores on
    /// drag-out / toggle. (#257)
    /// </summary>
    [Parameter] public bool Collapsible { get; set; }

    /// <summary>Percentage the panel occupies while collapsed. Default 0.
    /// Only meaningful when <see cref="Collapsible"/> is true.</summary>
    [Parameter] public double CollapsedSize { get; set; }

    /// <summary>The panel's content.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Additional CSS classes merged onto the panel.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures any unmatched attributes and applies them to the panel.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private double Size => Context?.GetPanelSize(Order) ?? DefaultSize;
    private bool IsCollapsed => Context?.IsPanelCollapsed(Order) ?? false;

    private string CssClass => Cx.Merge("relative", Class);

    protected override void OnInitialized()
    {
        // DefaultSize is consumed by the group: when no group-level DefaultSizes
        // are provided it seeds the shared size list from these registrations
        // (see ResizablePanelGroup.OnAfterRender). Collapse config travels with
        // the registration so the group can snap/restore this panel.
        Context?.RegisterPanel?.Invoke(Order, DefaultSize, MinSize, MaxSize, Collapsible, CollapsedSize);
    }

    // A panel removed at runtime (reorder / conditional render) must drop its
    // per-Order registration from the group; otherwise the group keeps stale
    // default-size / constraint / collapse-config / collapsed / pre-collapse
    // entries for an index no panel occupies anymore, and the group's
    // shrink-reconcile never fires (it keys off _panelDefaultSizes.Count, which
    // would never decrease). Without this the next panel that reuses the index
    // inherits the dead panel's constraints/collapse state. (#109)
    public void Dispose()
    {
        Context?.UnregisterPanel?.Invoke(Order);
    }
}

@namespace Lumeo
@implements IAsyncDisposable

@{
    var context = new ResizablePanelGroupContext(
        _groupId,
        Direction,
        EventCallback.Factory.Create<(int PanelIndex, double Delta)>(this, HandleDrag),
        GetPanelSize,
        _sizes.Count,
        RegisterPanel,
        GetPanelConstraints,
        IsPanelCollapsed,
        EventCallback.Factory.Create<int>(this, ToggleCollapse),
        UnregisterPanel
    );
}

<div id="@_groupId"
     class="@CssClass"
     data-panel-group-direction="@DirectionString"
     @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@inject IComponentInteropService Interop

@code {
    /// <summary>The group's <c>ResizablePanel</c>s interleaved with <c>ResizableHandle</c>s.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Axis panels are laid out and resized along. <see cref="Lumeo.Orientation.Horizontal"/> arranges panels side-by-side with vertical handles; <see cref="Lumeo.Orientation.Vertical"/> stacks them with horizontal handles. Defaults to <see cref="Lumeo.Orientation.Horizontal"/>.</summary>
    [Parameter] public Lumeo.Orientation Direction { get; set; } = Lumeo.Orientation.Horizontal;

    /// <summary>Explicit initial percentage sizes for each panel, in order. Takes precedence over each panel's own <c>DefaultSize</c> (but is itself superseded by <see cref="SavedLayout"/>). Length should match the number of panels.</summary>
    [Parameter] public double[]? DefaultSizes { get; set; }

    /// <summary>
    /// Optional previously-persisted panel sizes. The group seeds its layout
    /// from this on first render (taking precedence over panel
    /// <c>DefaultSize</c>s and <see cref="DefaultSizes"/>). Mirrors DataGrid /
    /// Tabs <c>SavedLayout</c>: the library never persists on its own — store
    /// the snapshot you receive from <see cref="OnLayout"/> and feed it back
    /// here on init.
    /// </summary>
    /// <example>
    /// <code>
    /// protected override void OnInitialized() => _layout = LoadFromStorage();
    ///
    /// &lt;ResizablePanelGroup SavedLayout="_layout" OnLayout="SaveToStorage"&gt;
    /// </code>
    /// </example>
    [Parameter] public ResizableLayout? SavedLayout { get; set; }

    /// <summary>
    /// Fires after every resize (drag, keyboard step, or collapse toggle) with
    /// the current panel sizes so the consumer can persist them. Pairs with
    /// <see cref="SavedLayout"/> to round-trip the layout through storage.
    /// </summary>
    [Parameter] public EventCallback<ResizableLayout> OnLayout { get; set; }

    /// <summary>Additional CSS classes merged onto the group's root container.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures any unmatched attributes and applies them to the group's root container.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _groupId = LumeoIds.New("resizable-group");
    private List<double> _sizes = new();
    private int _panelCount;
    private readonly Dictionary<int, (double MinSize, double MaxSize)> _panelConstraints = new();
    private readonly Dictionary<int, double> _panelDefaultSizes = new();
    // Per-panel collapse config + live collapsed state + the size remembered at
    // collapse time so a toggle/expand can restore it.
    private readonly Dictionary<int, (bool Collapsible, double CollapsedSize)> _collapseConfig = new();
    private readonly HashSet<int> _collapsed = new();
    private readonly Dictionary<int, double> _preCollapseSize = new();
    private bool _savedLayoutApplied;
    // True once a SavedLayout snapshot has been discarded for not matching the
    // live panel count — stops OnParametersSet from re-applying the same stale
    // snapshot on the next render and re-introducing the broken mixed layout.
    private bool _savedLayoutRejected;
    // True once _sizes has been populated for the initial panel set. A later
    // panel add/remove must RECONCILE the existing layout, not full-reseed it
    // back to the default split (which would wipe the user's drag/collapse).
    private bool _seeded;

    private string DirectionString => Direction == Lumeo.Orientation.Horizontal ? "horizontal" : "vertical";

    private string CssClass =>
        Direction == Lumeo.Orientation.Horizontal
            ? Cx.Merge("flex h-full w-full", Class)
            : Cx.Merge("flex h-full w-full flex-col", Class);

    protected override void OnParametersSet()
    {
        // SavedLayout wins over DefaultSizes: a persisted layout is the user's
        // last explicit choice. Applied once (per the guard) so a re-render
        // doesn't stomp a live drag.
        if (!_savedLayoutApplied && !_savedLayoutRejected && SavedLayout is { Sizes.Count: > 0 })
        {
            _sizes = new List<double>(SavedLayout.Sizes);
            _panelCount = _sizes.Count;
            _savedLayoutApplied = true;
            _seeded = true;
            return;
        }

        if (DefaultSizes is { Length: > 0 })
        {
            if (_sizes.Count != DefaultSizes.Length)
            {
                _sizes = new List<double>(DefaultSizes);
                _panelCount = DefaultSizes.Length;
            }
            _seeded = true;
        }
    }

    protected override void OnAfterRender(bool firstRender)
    {
        // A SavedLayout already seeded _sizes in OnParametersSet — keep it, but
        // ONLY when the snapshot's length matches the live registered panel set.
        // A stale/changed snapshot with a mismatched panel count (e.g. saved for
        // 2 panels, now rendering 3) would otherwise leave a broken mixed layout
        // (the surplus panels fall through to GetPanelSize's equal-share fallback,
        // so the totals don't sum to 100). When the counts disagree, discard the
        // stale snapshot and fall through to the normal default seeding below.
        if (_savedLayoutApplied && _sizes.Count > 0)
        {
            if (_panelDefaultSizes.Count == 0 || _panelDefaultSizes.Count == _sizes.Count) return;

            _savedLayoutApplied = false;
            _savedLayoutRejected = true;
            _seeded = false;
            _sizes = new List<double>();
        }

        // Panels register from their OnInitialized, which runs during this
        // component's first render — AFTER OnParametersSet has already executed.
        // When the consumer didn't supply group-level DefaultSizes, seed the
        // sizes here from the registered panels' DefaultSize and do a catch-up
        // render; without this, _sizes stayed empty and HandleDrag rejected
        // every drag (panelIndex + 1 >= _sizes.Count).
        if (DefaultSizes is { Length: > 0 }) return;
        if (_panelDefaultSizes.Count == 0) return;

        // Initial population: full-seed once from the registered DefaultSizes.
        if (!_seeded || _sizes.Count == 0)
        {
            SeedFromPanelDefaults();
            _seeded = true;
            _panelCount = _sizes.Count;
            StateHasChanged();
            return;
        }

        // The panel set changed AFTER the initial seed (a panel was added or
        // removed at runtime). Do NOT full-reseed — that would wipe the user's
        // dragged / collapsed layout back to the default split. Instead grow or
        // shrink the existing layout in place, preserving the survivors' ratios.
        if (_sizes.Count != _panelDefaultSizes.Count)
        {
            ReconcilePanelCount();
            _panelCount = _sizes.Count;
            StateHasChanged();
        }
    }

    // Build _sizes from the registered panel DefaultSizes, normalized to 100%.
    // Order keys are the documented zero-based panel indices; sort so the seeded
    // list lines up with GetPanelSize(order) lookups.
    private void SeedFromPanelDefaults()
    {
        var defaults = _panelDefaultSizes.OrderBy(kv => kv.Key).Select(kv => kv.Value).ToList();
        var total = defaults.Sum();
        _sizes = total > 0
            ? defaults.Select(d => d / total * 100.0).ToList()
            : Enumerable.Repeat(100.0 / defaults.Count, defaults.Count).ToList();
    }

    // Reconcile a live panel add/remove against the current (possibly user-edited)
    // _sizes without discarding the existing layout.
    //   - GROWTH: each newcomer takes its normalized DefaultSize share; the
    //     incumbents are proportionally scaled down to make room, so their
    //     relative split is preserved.
    //   - SHRINK: drop the removed slots and renormalize the survivors back to
    //     100, preserving their relative split.
    // Stale per-index collapse/restore state for indices that no longer exist is
    // pruned so it can't bleed into a future panel that reuses the index.
    private void ReconcilePanelCount()
    {
        var liveCount = _panelDefaultSizes.Count;
        var oldCount = _sizes.Count;

        if (liveCount > oldCount)
        {
            // Newcomers are the highest Order keys (panels append). Give each its
            // normalized DefaultSize share of 100; shrink incumbents to fit.
            var newDefaults = _panelDefaultSizes
                .OrderBy(kv => kv.Key)
                .Skip(oldCount)
                .Select(kv => kv.Value)
                .ToList();
            var defaultTotal = _panelDefaultSizes.Values.Sum();
            var newcomerShare = newDefaults
                .Select(d => defaultTotal > 0 ? d / defaultTotal * 100.0 : 100.0 / liveCount)
                .ToList();
            var totalNewcomer = newcomerShare.Sum();

            var incumbentSum = _sizes.Sum();
            var scale = incumbentSum > 0 ? (100.0 - totalNewcomer) / incumbentSum : 0.0;
            for (var i = 0; i < _sizes.Count; i++)
                _sizes[i] *= scale;
            _sizes.AddRange(newcomerShare);
        }
        else
        {
            // SHRINK: keep the leading survivors, renormalize to 100.
            _sizes = _sizes.Take(liveCount).ToList();
            var survivorSum = _sizes.Sum();
            if (survivorSum > 0)
                for (var i = 0; i < _sizes.Count; i++)
                    _sizes[i] = _sizes[i] / survivorSum * 100.0;
            else
                _sizes = Enumerable.Repeat(100.0 / liveCount, liveCount).ToList();

            // Drop collapse/restore bookkeeping for indices that no longer exist.
            _collapsed.RemoveWhere(i => i >= liveCount);
            foreach (var key in _preCollapseSize.Keys.Where(k => k >= liveCount).ToList())
                _preCollapseSize.Remove(key);
        }
    }

    private async Task EmitLayoutAsync()
    {
        if (OnLayout.HasDelegate)
            await OnLayout.InvokeAsync(new ResizableLayout(new List<double>(_sizes)));
    }

    private double GetPanelSize(int index)
    {
        if (index >= 0 && index < _sizes.Count)
        {
            return _sizes[index];
        }

        // Fallback: equal distribution
        var count = _panelCount > 0 ? _panelCount : 1;
        return 100.0 / count;
    }

    private void RegisterPanel(int order, double defaultSize, double minSize, double maxSize, bool collapsible, double collapsedSize)
    {
        _panelDefaultSizes[order] = defaultSize;
        _panelConstraints[order] = (minSize, maxSize);
        _collapseConfig[order] = (collapsible, collapsedSize);
    }

    // Called from ResizablePanel.Dispose when a panel is removed at runtime.
    // Drops the panel's per-Order entries from every group map so no stale
    // constraint / collapse config / collapsed flag / remembered pre-collapse
    // size survives for an index no live panel occupies. Removing from
    // _panelDefaultSizes also lets OnAfterRender's count-mismatch shrink-reconcile
    // fire (it compares _sizes.Count against _panelDefaultSizes.Count). _sizes
    // itself is renormalized by ReconcilePanelCount on the following render, so
    // we don't touch it here (the panel set isn't fully torn down yet).
    private void UnregisterPanel(int order)
    {
        _panelDefaultSizes.Remove(order);
        _panelConstraints.Remove(order);
        _collapseConfig.Remove(order);
        _collapsed.Remove(order);
        _preCollapseSize.Remove(order);
    }

    private (double MinSize, double MaxSize) GetPanelConstraints(int index) =>
        _panelConstraints.TryGetValue(index, out var c) ? c : (0.0, 100.0);

    private (bool Collapsible, double CollapsedSize) GetCollapseConfig(int index) =>
        _collapseConfig.TryGetValue(index, out var c) ? c : (false, 0.0);

    private bool IsPanelCollapsed(int index) => _collapsed.Contains(index);

    // Public collapse toggle (wired to ResizablePanel.Collapsible UI / consumer
    // code via the cascading context). Collapsing parks the panel at its
    // CollapsedSize and hands the freed space to the next panel; expanding
    // restores the size remembered at collapse time (falling back to its
    // DefaultSize).
    private async Task ToggleCollapse(int index)
    {
        if (index < 0 || index >= _sizes.Count) return;
        var (collapsible, collapsedSize) = GetCollapseConfig(index);
        if (!collapsible) return;

        // Pair the panel with a neighbour to absorb / release the delta — prefer
        // the next panel, fall back to the previous one (last panel collapse).
        var neighbour = index + 1 < _sizes.Count ? index + 1 : index - 1;
        if (neighbour < 0) return;

        if (_collapsed.Contains(index))
        {
            var restore = _preCollapseSize.TryGetValue(index, out var s) ? s : _panelDefaultSizes.GetValueOrDefault(index, 50);
            var neighbourMin = GetPanelConstraints(neighbour).MinSize;
            // Reclaim space from the neighbour, but never push it below its MinSize.
            var delta = Math.Min(restore - _sizes[index], Math.Max(0, _sizes[neighbour] - neighbourMin));
            _sizes[index] += delta;
            _sizes[neighbour] -= delta;
            _collapsed.Remove(index);
        }
        else
        {
            _preCollapseSize[index] = _sizes[index];
            var freed = _sizes[index] - collapsedSize;
            _sizes[index] = collapsedSize;
            _sizes[neighbour] += freed;
            _collapsed.Add(index);
        }

        StateHasChanged();
        await EmitLayoutAsync();
    }

    private async Task HandleDrag((int PanelIndex, double Delta) args)
    {
        var (panelIndex, deltaPx) = args;

        if (panelIndex < 0 || panelIndex + 1 >= _sizes.Count)
            return;

        // Convert delta from pixels to percentage of total group dimension
        var dimension = Direction == Lumeo.Orientation.Horizontal ? "width" : "height";
        var totalSize = await Interop.GetElementDimension(_groupId, dimension);

        if (totalSize <= 0)
            return;

        var deltaPercent = (deltaPx / totalSize) * 100.0;

        var leftConstraints = GetPanelConstraints(panelIndex);
        var rightConstraints = GetPanelConstraints(panelIndex + 1);
        var pairTotal = _sizes[panelIndex] + _sizes[panelIndex + 1];
        var desiredLeft = _sizes[panelIndex] + deltaPercent;

        // Collapsible panels snap to CollapsedSize when over-dragged below half
        // their MinSize (matching Splitter), instead of clamping at MinSize.
        var (leftCollapsible, leftCollapsed) = GetCollapseConfig(panelIndex);
        var (rightCollapsible, rightCollapsed) = GetCollapseConfig(panelIndex + 1);
        if (leftCollapsible && desiredLeft < leftConstraints.MinSize - (leftConstraints.MinSize - leftCollapsed) / 2)
        {
            _preCollapseSize[panelIndex] = _sizes[panelIndex];
            _sizes[panelIndex] = leftCollapsed;
            _sizes[panelIndex + 1] = pairTotal - leftCollapsed;
            _collapsed.Add(panelIndex);
            StateHasChanged();
            await EmitLayoutAsync();
            return;
        }
        if (rightCollapsible && (pairTotal - desiredLeft) < rightConstraints.MinSize - (rightConstraints.MinSize - rightCollapsed) / 2)
        {
            _preCollapseSize[panelIndex + 1] = _sizes[panelIndex + 1];
            _sizes[panelIndex + 1] = rightCollapsed;
            _sizes[panelIndex] = pairTotal - rightCollapsed;
            _collapsed.Add(panelIndex + 1);
            StateHasChanged();
            await EmitLayoutAsync();
            return;
        }

        // Enforce per-panel min/max constraints by CLAMPING (not rejecting):
        // a fast drag whose accumulated delta overshoots a boundary lands
        // exactly ON the boundary instead of stalling short of it.
        var minLeft = Math.Max(leftConstraints.MinSize, pairTotal - rightConstraints.MaxSize);
        var maxLeft = Math.Min(leftConstraints.MaxSize, pairTotal - rightConstraints.MinSize);
        if (minLeft > maxLeft) return; // unsatisfiable constraints — keep current sizes

        var newLeft = Math.Clamp(desiredLeft, minLeft, maxLeft);

        _sizes[panelIndex] = newLeft;
        _sizes[panelIndex + 1] = pairTotal - newLeft;
        // A resize that lands either panel back at/above its MinSize clears its
        // collapsed flag.
        if (_sizes[panelIndex] >= leftConstraints.MinSize) _collapsed.Remove(panelIndex);
        if (_sizes[panelIndex + 1] >= rightConstraints.MinSize) _collapsed.Remove(panelIndex + 1);

        StateHasChanged();
        await EmitLayoutAsync();
    }

    public ValueTask DisposeAsync()
    {
        return ValueTask.CompletedTask;
    }

    public record ResizablePanelGroupContext(
        string GroupId,
        Lumeo.Orientation Direction,
        EventCallback<(int PanelIndex, double Delta)> OnHandleDrag,
        Func<int, double> GetPanelSize,
        int PanelCount,
        Action<int, double, double, double, bool, double> RegisterPanel,
        Func<int, (double MinSize, double MaxSize)> GetPanelConstraints,
        Func<int, bool> IsPanelCollapsed,
        EventCallback<int> ToggleCollapse,
        Action<int> UnregisterPanel
    );
}
